parameters.content:
/**
 * Email notification adapter — delivers notifications via email.
 *
 * Features:
 * - Template rendering with {{variable}} placeholder substitution
 * - Recipient validation and resolution (user ID → email mapping)
 * - Priority-based email headers (X-Priority)
 * - Configurable sender information
 * - Built-in templates for common notification types
 *
 * Template Usage:
 * To use a template, include a `template` key in the payload's metadata:
 *   metadata: { template: 'order-confirmation', orderId: 'ORD-001', customerName: 'Alice' }
 * Template variables are pulled from the metadata object. The `senderName`
 * variable is automatically populated from the adapter's config.
 *
 * Recipient Resolution:
 * The adapter can resolve non-email identifiers (e.g., user IDs) to email
 * addresses via a mapping registered with registerRecipient(). If no mapping
 * exists, the recipient is used as-is and must be a valid email address.
 *
 * Implements: NotificationAdapter (channel: 'email')
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the email adapter.
 */
export interface EmailAdapterConfig {
  /** Sender email address (the "from" address) */
  fromAddress: string;
  /** Sender display name */
  fromName: string;
  /** Whether the adapter is enabled. When false, isAvailable() returns false. */
  enabled: boolean;
}

/** Default email adapter configuration. */
export const defaultEmailConfig: EmailAdapterConfig = {
  fromAddress: 'noreply@taskflow.example.com',
  fromName: 'TaskFlow Pro',
  enabled: true,
};

/**
 * Represents a composed email message ready for delivery.
 * Used internally by the adapter to structure outgoing emails.
 */
export interface EmailMessage {
  /** Sender address */
  from: string;
  /** Recipient address */
  to: string;
  /** Email subject line */
  subject: string;
  /** Plain text body */
  body: string;
  /** Optional HTML body (populated when a template with htmlBody is used) */
  htmlBody?: string;
  /** Priority flag for email headers */
  priority: string;
  /** Optional additional headers */
  headers?: Record<string, string>;
}

/**
 * Email template with placeholder support.
 * Placeholders use the {{variableName}} syntax and are replaced
 * with values from the template variables at render time.
 */
export interface EmailTemplate {
  /** Unique template identifier */
  id: string;
  /** Subject line template with {{placeholder}} support */
  subject: string;
  /** Plain-text body template with {{placeholder}} support */
  body: string;
  /** Optional HTML body template with {{placeholder}} support */
  htmlBody?: string;
}

/**
 * Maps notification priority levels to standard X-Priority email header values.
 * 1 = Highest, 3 = Normal, 5 = Lowest
 */
const PRIORITY_HEADERS: Record<string, string> = {
  low: '5',
  normal: '3',
  high: '2',
  urgent: '1',
};

/** Basic email address validation pattern. */
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Creates the set of built-in email templates for common notification types.
 */
function createBuiltInTemplates(): EmailTemplate[] {
  return [
    {
      id: 'order-confirmation',
      subject: 'Order Confirmation: {{orderId}}',
      body: [
        'Dear {{customerName}},',
        '',
        'Thank you for your order! Here are your order details:',
        '',
        'Order ID: {{orderId}}',
        'Items: {{itemSummary}}',
        'Total: ${{total}}',
        '',
        'We will notify you when your order status changes.',
        '',
        'Best regards,',
        'The {{senderName}} Team',
      ].join('\n'),
    },
    {
      id: 'order-status-update',
      subject: 'Order Update: {{orderId}}',
      body: [
        'Dear {{customerName}},',
        '',
        'Your order {{orderId}} has been updated.',
        '',
        'Previous Status: {{previousStatus}}',
        'New Status: {{newStatus}}',
        '',
        'Thank you for your patience!',
        '',
        'Best regards,',
        'The {{senderName}} Team',
      ].join('\n'),
    },
    {
      id: 'welcome',
      subject: 'Welcome to {{senderName}}, {{customerName}}!',
      body: [
        'Dear {{customerName}},',
        '',
        'Welcome to {{senderName}}! We are excited to have you on board.',
        '',
        'If you have any questions, please do not hesitate to reach out.',
        '',
        'Best regards,',
        'The {{senderName}} Team',
      ].join('\n'),
    },
  ];
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private config: EmailAdapterConfig;
  private sentEmails: EmailMessage[] = [];
  private templates: Map<string, EmailTemplate> = new Map();
  private recipientMap: Map<string, string> = new Map();

  constructor(config?: Partial<EmailAdapterConfig>) {
    this.config = { ...defaultEmailConfig, ...config };
    this.loadBuiltInTemplates();
  }

  // ---------------------------------------------------------------------------
  // NotificationAdapter Interface
  // ---------------------------------------------------------------------------

  /**
   * Send an email notification.
   *
   * Processing pipeline:
   * 1. Check adapter availability.
   * 2. Resolve recipient (map user IDs to emails if registered).
   * 3. Validate the resolved email address.
   * 4. Apply template rendering if `metadata.template` is specified.
   * 5. Compose the email message with headers.
   * 6. Deliver (currently in-memory; replace with SMTP/API for production).
   * 7. Return delivery result.
   *
   * @param payload - The notification to deliver via email.
   * @returns Result indicating delivery success or failure.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!this.isAvailable()) {
      return {
        success: false,
        errorMessage: 'Email adapter is not available (disabled in configuration)',
      };
    }

    try {
      // Step 1: Resolve recipient (user ID → email, or passthrough)
      const resolvedRecipient = this.resolveRecipient(payload.recipient);

      // Step 2: Validate the resolved email address
      if (!this.validateEmail(resolvedRecipient)) {
        this.logger.warn(`Invalid recipient email: ${resolvedRecipient}`);
        return {
          success: false,
          errorMessage: `Invalid recipient email address: ${resolvedRecipient}`,
        };
      }

      // Step 3: Apply template rendering if specified in metadata
      const rendered = this.applyTemplate(payload);

      // Step 4: Compose the email with resolved data
      const resolvedPayload: NotificationPayload = {
        ...payload,
        recipient: resolvedRecipient,
        subject: rendered.subject,
        body: rendered.body,
      };
      const email = this.composeEmail(resolvedPayload);

      // Add HTML body if template provided one
      if (rendered.htmlBody) {
        email.htmlBody = rendered.htmlBody;
      }

      // Step 5: Deliver (in-memory store; replace with real transport in production)
      this.logger.info(
        `Email sent: to=${email.to}, subject="${email.subject}", from=${email.from}`,
      );
      this.sentEmails.push(email);

      return {
        success: true,
        adapterResponse: {
          messageId: `email-${Date.now()}`,
          from: email.from,
          to: email.to,
        },
      };
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown email delivery error';
      this.logger.error(`Email delivery failed: ${errorMessage}`);
      return {
        success: false,
        errorMessage,
      };
    }
  }

  /**
   * Check if the email adapter is available for sending.
   */
  isAvailable(): boolean {
    return this.config.enabled;
  }

  // ---------------------------------------------------------------------------
  // Template Management
  // ---------------------------------------------------------------------------

  /**
   * Register a custom email template.
   * If a template with the same ID already exists, it is replaced.
   *
   * @param template - The template to register.
   */
  registerTemplate(template: EmailTemplate): void {
    this.templates.set(template.id, template);
    this.logger.info(`Template registered: ${template.id}`);
  }

  /**
   * Get a registered template by ID.
   *
   * @param id - The template identifier.
   * @returns The template, or undefined if not found.
   */
  getTemplate(id: string): EmailTemplate | undefined {
    return this.templates.get(id);
  }

  /**
   * Get all registered template IDs.
   */
  getTemplateIds(): string[] {
    return [...this.templates.keys()];
  }

  /**
   * Render a template with the given variables.
   * Replaces {{variableName}} placeholders with values from the vars object.
   * The `senderName` variable is automatically populated from the adapter config
   * unless explicitly provided in vars.
   *
   * Unresolved placeholders are left as-is in the output.
   *
   * @param templateId - The ID of the template to render.
   * @param vars - Key-value pairs for placeholder substitution.
   * @returns The rendered subject, body, and optional htmlBody.
   * @throws Error if the template ID is not registered.
   */
  renderTemplate(
    templateId: string,
    vars: Record<string, string>,
  ): { subject: string; body: string; htmlBody?: string } {
    const template = this.templates.get(templateId);
    if (!template) {
      throw new Error(`Email template not found: ${templateId}`);
    }

    const allVars: Record<string, string> = {
      senderName: this.config.fromName,
      ...vars,
    };

    return {
      subject: this.interpolate(template.subject, allVars),
      body: this.interpolate(template.body, allVars),
      htmlBody: template.htmlBody
        ? this.interpolate(template.htmlBody, allVars)
        : undefined,
    };
  }

  // ---------------------------------------------------------------------------
  // Recipient Resolution
  // ---------------------------------------------------------------------------

  /**
   * Register a mapping from a non-email identifier to an email address.
   * This allows the adapter to resolve user IDs, usernames, etc. to
   * deliverable email addresses.
   *
   * @param identifier - The non-email identifier (e.g., user ID).
   * @param email - The email address to map it to.
   */
  registerRecipient(identifier: string, email: string): void {
    this.recipientMap.set(identifier, email);
  }

  /**
   * Resolve a recipient identifier to an email address.
   * If a mapping is registered for the identifier, returns the mapped email.
   * Otherwise returns the recipient as-is (trimmed and lowercased).
   *
   * @param recipient - The recipient identifier or email address.
   * @returns The resolved email address.
   */
  resolveRecipient(recipient: string): string {
    const mapped = this.recipientMap.get(recipient);
    if (mapped) {
      return mapped;
    }
    return recipient.trim().toLowerCase();
  }

  /**
   * Validate that a string is a well-formed email address.
   *
   * @param email - The string to validate.
   * @returns true if the string is a valid email format.
   */
  validateEmail(email: string): boolean {
    return EMAIL_REGEX.test(email);
  }

  // ---------------------------------------------------------------------------
  // Test Helpers
  // ---------------------------------------------------------------------------

  /**
   * Get all emails sent by this adapter (useful for testing).
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Clear the sent emails log (useful for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }

  /**
   * Get the current configuration.
   */
  getConfig(): Readonly<EmailAdapterConfig> {
    return { ...this.config };
  }

  // ---------------------------------------------------------------------------
  // Private Methods
  // ---------------------------------------------------------------------------

  /**
   * Load built-in templates into the template registry.
   */
  private loadBuiltInTemplates(): void {
    for (const template of createBuiltInTemplates()) {
      this.templates.set(template.id, template);
    }
  }

  /**
   * Apply template rendering if a template is specified in the payload metadata.
   * If no template is specified (or the template is not found), returns the
   * raw subject and body from the payload unchanged.
   *
   * @param payload - The notification payload.
   * @returns Rendered subject, body, and optional htmlBody.
   */
  private applyTemplate(payload: NotificationPayload): {
    subject: string;
    body: string;
    htmlBody?: string;
  } {
    const templateId = payload.metadata?.['template'];
    if (!templateId || !this.templates.has(templateId)) {
      return { subject: payload.subject, body: payload.body };
    }

    // Build template variables from metadata (excluding the 'template' key)
    const vars: Record<string, string> = {};
    if (payload.metadata) {
      for (const [key, value] of Object.entries(payload.metadata)) {
        if (key !== 'template') {
          vars[key] = value;
        }
      }
    }

    return this.renderTemplate(templateId, vars);
  }

  /**
   * Interpolate {{placeholder}} variables in a template string.
   * Unresolved placeholders are left as-is.
   *
   * @param text - The template string.
   * @param vars - Key-value pairs for substitution.
   * @returns The interpolated string.
   */
  private interpolate(text: string, vars: Record<string, string>): string {
    return text.replace(/\{\{(\w+)\}\}/g, (match, key: string) => {
      return vars[key] !== undefined ? vars[key] : match;
    });
  }

  /**
   * Compose an EmailMessage from a NotificationPayload.
   * Adds priority headers and merges metadata as email headers.
   *
   * @param payload - The notification payload (with resolved recipient).
   * @returns The composed email message.
   */
  private composeEmail(payload: NotificationPayload): EmailMessage {
    const email: EmailMessage = {
      from: `${this.config.fromName} <${this.config.fromAddress}>`,
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      priority: payload.priority,
    };

    // Start with priority header
    const headers: Record<string, string> = {
      'X-Priority': PRIORITY_HEADERS[payload.priority] ?? '3',
    };

    // Merge adapter-specific metadata as email headers (excluding 'template' key)
    if (payload.metadata) {
      for (const [key, value] of Object.entries(payload.metadata)) {
        if (key !== 'template') {
          headers[key] = value;
        }
      }
    }

    email.headers = headers;

    return email;
  }
}

