      expect(email.body).toContain('New Status: shipped');
      // Priority header set
      expect(email.headers?.['X-Priority']).toBe('2');
      // From address from config
      expect(email.from).toBe('TaskFlow Pro <noreply@taskflow.example.com>');
    });

